  records         = [aws_elastic_beanstalk_environment.myenv_eu_west.cname]
  health_check_id = aws_route53_health_check.eu_west.id
}

resource "aws_route53_record" "primary_default" {
  zone_id = aws_route53_zone.main.zone_id
