    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_PASSWORD"
    value     = random_password.db_password.result
  }
}

# Route 53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = "example.com"
}

# Route 53 Health Checks
resource "aws_route53_health_check" "us_east" {
  fqdn              = aws_elastic_beanstalk_environment.myenv_us_east.cname
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = 3
  request_interval  = 30

  tags = {
    Name = "us-east-1-health-check"
  }
}

resource "aws_route53_health_check" "eu_west" {
  fqdn              = aws_elastic_beanstalk_environment.myenv_eu_west.cname
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = 3
  request_interval  = 30

  tags = {
    Name = "eu-west-1-health-check"
  }
}

# Route 53 Records for multi-region failover
resource "aws_route53_record" "us_east_1" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "us-east-1.example.com"
  type    = "CNAME"
  ttl     = 60

  weighted_routing_policy {
    weight = 100
  }

  set_identifier  = "us-east-1"
  records         = [aws_elastic_beanstalk_environment.myenv_us_east.cname]
  health_check_id = aws_route53_health_check.us_east.id
}

resource "aws_route53_record" "eu_west_1" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "eu-west-1.example.com"
  type    = "CNAME"
  ttl     = 60

  weighted_routing_policy {
    weight = 100
  }

  set_identifier  = "eu-west-1"
  records         = [aws_elastic_beanstalk_environment.myenv_eu_west.cname]
  health_check_id = aws_route53_health_check.eu_west.id
}

# Primary Route 53 record with geolocation routing
resource "aws_route53_record" "primary_us" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www.example.com"
  type    = "CNAME"
  ttl     = 60

  geolocation_routing_policy {
    continent = "NA"
  }

  set_identifier  = "us-east-1"
  records         = [aws_elastic_beanstalk_environment.myenv_us_east.cname]
  health_check_id = aws_route53_health_check.us_east.id
}

resource "aws_route53_record" "primary_eu" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www.example.com"
  type    = "CNAME"
  ttl     = 60

  geolocation_routing_policy {
    continent = "EU"
  }

  set_identifier  = "eu-west-1"
  records         = [aws_elastic_beanstalk_environment.myenv_eu_west.cname]
  health_check_id = aws_route53_health_check.eu_west.id
}

resource "aws_route53_record" "primary_default" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www.example.com"
  type    = "CNAME"
  ttl     = 60

  geolocation_routing_policy {
    country = "*"
  }

  set_identifier  = "default"
  records         = [aws_elastic_beanstalk_environment.myenv_us_east.cname]
  health_check_id = aws_route53_health_check.us_east.id
}
