resource "aws_codebuild_project" "example" {
  name          = "example-codebuild-project"
  description   = "Example CodeBuild project with secondary sources and artifacts"
  build_timeout = 60
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = "my-primary-artifacts-bucket"
    name = "primary-artifact"
  }

  secondary_artifacts {
    artifact_identifier = "secondary_artifact_1"
    type               = "S3"
    location           = "my-secondary-artifacts-bucket-1"
    name               = "secondary-artifact-1"
  }

  secondary_artifacts {
    artifact_identifier = "secondary_artifact_2"
    type               = "S3"
    location           = "my-secondary-artifacts-bucket-2"
    name               = "secondary-artifact-2"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                      = "aws/codebuild/standard:5.0"
    type                       = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "ENV"
      value = "production"
    }

    environment_variable {
      name  = "REGION"
      value = "us-east-1"
    }

    environment_variable {
      name  = "API_KEY"
      value = "example-api-key"
      type  = "PLAINTEXT"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example/primary-repo.git"
    git_clone_depth = 1
    buildspec       = "buildspec.yml"
  }

  secondary_sources {
    source_identifier = "secondary_source_1"
    type             = "GITHUB"
    location         = "https://github.com/example/secondary-repo-1.git"
    git_clone_depth  = 1
  }

  secondary_sources {
    source_identifier = "secondary_source_2"
    type             = "GITHUB"
    location         = "https://github.com/example/secondary-repo-2.git"
    git_clone_depth  = 1
  }

  tags = {
    Environment = "Production"
    Project     = "Example"
  }
}

