resource "aws_lex_bot" "trip_booking" {
  name                        = "TripBookingBot"
  description                 = "Bot for booking trips and travel arrangements"
  process_behavior            = "BUILD"
  locale                      = "en-US"
  child_directed              = false
  detect_sentiment            = true
  enable_model_improvements   = true
  idle_session_ttl_in_seconds = 600
  voice_id                    = "Joanna"
  create_version              = true
  nlu_intent_confidence_threshold = 0.5

  abort_statement {
    message {
      content      = "Sorry, I am not able to assist at this time. Please try again later."
      content_type = "PlainText"
    }
  }

  clarification_prompt {
    max_attempts = 2

    message {
      content      = "I didn't understand you, what would you like to do? You can say things like 'Book a trip' or 'Cancel my booking'."
      content_type = "PlainText"
    }
  }

  intent {
    intent_name    = "BookTrip"
    intent_version = "$LATEST"
  }

  intent {
    intent_name    = "CancelBooking"
    intent_version = "$LATEST"
  }
}

resource "aws_lex_intent" "book_trip" {
  name        = "BookTrip"
  description = "Intent to book a trip"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "I want to book a trip",
    "Book a trip to {Destination}",
    "I'd like to travel to {Destination}",
    "Book a flight and hotel",
  ]

  slot {
    name        = "Destination"
    description = "Destination city"
    priority    = 1
    slot_constraint = "Required"
    slot_type   = "AMAZON.City"

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "Where would you like to travel to?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "CheckInDate"
    description = "Check-in date"
    priority    = 2
    slot_constraint = "Required"
    slot_type   = "AMAZON.DATE"

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What is your check-in date?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "Nights"
    description = "Number of nights"
    priority    = 3
    slot_constraint = "Required"
    slot_type   = "AMAZON.NUMBER"

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "How many nights will you be staying?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "Okay, I have you down for a {Nights} night stay in {Destination} starting on {CheckInDate}. Should I book the reservation?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I have cancelled your reservation in progress."
      content_type = "PlainText"
    }
  }
}

resource "aws_lex_intent" "cancel_booking" {
  name        = "CancelBooking"
  description = "Intent to cancel a booking"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "Cancel my booking",
    "I want to cancel my reservation",
    "Cancel my trip",
  ]

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "Are you sure you want to cancel your booking?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, your booking will not be cancelled."
      content_type = "PlainText"
    }
  }
}

