resource "aws_lex_intent" "order_pizza" {
  name        = "OrderPizza"
  description = "Intent to order a pizza"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "I want to order a pizza",
    "Order a pizza",
    "I'd like a pizza",
    "Can I get a pizza"
  ]

  slot {
    name        = "PizzaSize"
    description = "Size of the pizza"
    slot_constraint = "Required"
    slot_type   = "AMAZON.AlphaNumeric"
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What size pizza would you like? Small, Medium, or Large?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "PizzaType"
    description = "Type of pizza"
    slot_constraint = "Required"
    slot_type   = "AMAZON.AlphaNumeric"
    priority    = 2

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What type of pizza would you like?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "Should I order your {PizzaSize} {PizzaType} pizza?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I have cancelled your order."
      content_type = "PlainText"
    }
  }
}

resource "aws_lex_intent" "check_order_status" {
  name        = "CheckOrderStatus"
  description = "Intent to check order status"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "Where is my order",
    "Check my order status",
    "What's the status of my pizza",
    "Is my pizza ready"
  ]

  slot {
    name        = "OrderNumber"
    description = "Order number to check"
    slot_constraint = "Required"
    slot_type   = "AMAZON.Number"
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What is your order number?"
        content_type = "PlainText"
      }
    }
  }
}

resource "aws_lex_intent" "cancel_order" {
  name        = "CancelOrder"
  description = "Intent to cancel an order"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "Cancel my order",
    "I want to cancel my pizza",
    "Cancel order",
    "Stop my order"
  ]

  slot {
    name        = "OrderNumber"
    description = "Order number to cancel"
    slot_constraint = "Required"
    slot_type   = "AMAZON.Number"
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What is the order number you want to cancel?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "Are you sure you want to cancel order {OrderNumber}?"
      content_type = "PlainText"
    }
  }

