  intent {
    intent_name    = "OrderPizza"
    intent_version = "1"
  }

  create_version = false
}

resource "aws_lex_intent" "order_pizza" {
  name        = "OrderPizza"
  description = "Intent to order a pizza"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "I want to order a pizza",
    "Can I get a pizza",
    "I'd like a pizza please",
    "Pizza time",
    "Order pizza",
    "I want pizza"
  ]

  slot {
    name        = "PizzaSize"
    description = "Size of the pizza"
    slot_constraint = "Required"
    slot_type   = "PizzaSize"
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What size pizza would you like? Small, Medium, or Large?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "PizzaTopping"
    description = "Pizza topping"
    slot_constraint = "Required"
    slot_type   = "PizzaTopping"
    priority    = 2

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What topping would you like? We have cheese, pepperoni, veggie, or hawaiian!"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "Great! So you want a {PizzaSize} {PizzaTopping} pizza. Is that correct?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, no problem! Let's start over. What pizza would you like?"
      content_type = "PlainText"
    }
  }
}

resource "aws_lex_slot_type" "pizza_size" {
  name        = "PizzaSize"
  description = "Available pizza sizes"

  enumeration_value {
    value = "small"
    synonyms = ["little", "tiny", "small"]
  }

  enumeration_value {
    value = "medium"
    synonyms = ["regular", "normal", "medium"]
  }

  enumeration_value {
    value = "large"
    synonyms = ["big", "huge", "large", "extra large"]
  }

  value_selection_strategy = "TOP_RESOLUTION"
}

resource "aws_lex_slot_type" "pizza_topping" {
  name        = "PizzaTopping"
  description = "Available pizza toppings"

  enumeration_value {
    value = "cheese"
    synonyms = ["cheese", "plain cheese"]
  }

  enumeration_value {
    value = "pepperoni"
    synonyms = ["pepperoni", "pepperoni pizza"]
  }

  enumeration_value {
    value = "veggie"
    synonyms = ["veggie", "vegetable", "vegetables", "veggies"]
  }

  enumeration_value {
    value = "hawaiian"
    synonyms = ["hawaiian", "pineapple", "ham and pineapple"]
  }

  value_selection_strategy = "TOP_RESOLUTION"
}

