resource "aws_lex_intent" "order_pizza" {
  name = "OrderPizza"
  description = "Intent to order a pizza"

  fulfillment_activity {
    type = "CodeHook"
    code_hook {
      uri             = aws_lambda_function.pizza_fulfillment.arn
      message_version = "1.0"
    }
  }

  sample_utterances = [
    "I would like to order a pizza",
    "Order a pizza",
    "I want a pizza",
    "Can I get a pizza",
    "Pizza please"
  ]

  slot {
    name        = "PizzaSize"
    description = "Size of the pizza"
    slot_constraint = "Required"
    slot_type   = "AMAZON.AlphaNumeric"
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What size pizza would you like? Small, Medium, or Large?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "PizzaType"
    description = "Type of pizza"
    slot_constraint = "Required"
    slot_type   = "AMAZON.AlphaNumeric"
    priority    = 2

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What type of pizza would you like? Pepperoni, Cheese, or Vegetarian?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "You want to order a {PizzaSize} {PizzaType} pizza. Is that correct?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I have cancelled your pizza order."
      content_type = "PlainText"
    }
  }
}

resource "aws_lex_bot" "pizza_order_bot" {
  name                        = "PizzaOrderBot"
  description                 = "Bot to order pizzas"
  idle_session_ttl_in_seconds = 600
  process_behavior            = "BUILD"
  locale                      = "en-US"
  child_directed              = false
  voice_id                    = "Salli"

  abort_statement {
    message {
