resource "aws_kendra_index" "example" {
  name        = "example-kendra-index"
  description = "Example Kendra index with user group resolution configuration"
  role_arn    = aws_iam_role.kendra.arn
  edition     = "DEVELOPER_EDITION"

  user_group_resolution_configuration {
    user_group_resolution_mode = "AWS_SSO"
  }

  tags = {
    Name = "example-kendra-index"
  }
}

resource "aws_iam_role" "kendra" {
  name = "kendra-index-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "kendra" {
  name = "kendra-index-policy"
  role = aws_iam_role.kendra.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "cloudwatch:PutMetricData"
        ]
        Resource = "*"
        Condition = {
          StringEquals = {
            "cloudwatch:namespace" = "AWS/Kendra"
          }
        }
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:log-group:/aws/kendra/*"
      }
    ]
  })
}
