extracted_code:
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

resource "aws_ami_copy" "amazon_linux_2_custom" {
  name              = "amazon-linux-2-custom-${formatdate("YYYY-MM-DD-hhmm", timestamp())}"
  source_ami_id     = data.aws_ami.amazon_linux_2.id
  source_ami_region = data.aws_ami.amazon_linux_2.region

  tags = {
    Name = "Amazon Linux 2 Custom CPU Configuration"
  }
}

resource "aws_ami" "custom_cpu_config" {
  name                = "amazon-linux-2-cpu-config-${formatdate("YYYY-MM-DD-hhmm", timestamp())}"
  virtualization_type = "hvm"
  root_device_name    = "/dev/xvda"
  imds_support        = "v2.0"

  ebs_block_device {
    device_name = "/dev/xvda"
    snapshot_id = data.aws_ami.amazon_linux_2.root_snapshot_id
    volume_size = 8
    volume_type = "gp2"
  }

  boot_mode = "uefi-preferred"

  cpu_options {
    core_count       = 2
    threads_per_core = 2
  }
}

