        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Role for EC2 Fleet Service
resource "aws_iam_role" "ec2_fleet_service" {
  name = "ec2-fleet-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2fleet.amazonaws.com"
        }
      }
    ]
  })
}

