  byte_length = 8
}

resource "aws_s3_object" "plugin_zip" {
  bucket = aws_s3_bucket.plugin_bucket.id
  key    = "debezium.zip"
  source = "debezium.zip"
}

resource "aws_mskconnect_custom_plugin" "debezium" {
  name         = "debezium-connector-plugin"
  content_type = "ZIP"

  location {
    s3 {
      bucket_arn = aws_s3_bucket.plugin_bucket.arn
      file_key   = aws_s3_object.plugin_zip.key
    }
  }
}

resource "aws_iam_role" "msk_connect_role" {
  name = "msk-connect-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
