  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "neptune-subnet-1"
  }
}

resource "aws_subnet" "subnet2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[1]

  tags = {
    Name = "neptune-subnet-2"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Neptune Subnet Group
resource "aws_neptune_subnet_group" "main" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.subnet1.id, aws_subnet.subnet2.id]

  tags = {
    Name = "neptune-subnet-group"
  }
}

# Security Group to restrict access to the two subnets
resource "aws_security_group" "neptune" {
  name        = "neptune-security-group"
  description = "Allow Neptune access from specific subnets only"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "Neptune from subnet 1"
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.subnet1.cidr_block]
  }

  ingress {
    description = "Neptune from subnet 2"
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.subnet2.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-sg"
  }
}

# Neptune Cluster Parameter Group
resource "aws_neptune_cluster_parameter_group" "main" {
  family      = "neptune1.2"
  name        = "neptune-custom-params"
  description = "Custom parameter group for Neptune cluster"

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }

  tags = {
    Name = "neptune-custom-params"
  }
}

# Neptune Cluster
resource "aws_neptune_cluster" "main" {
  cluster_identifier                   = "neptune-cluster"
  engine                              = "neptune"
  engine_version                      = "1.2.1.0"
  backup_retention_period             = 5
  preferred_backup_window             = "07:00-09:00"
  skip_final_snapshot                 = true
  neptune_subnet_group_name           = aws_neptune_subnet_group.main.name
  neptune_cluster_parameter_group_name = aws_neptune_cluster_parameter_group.main.name
  vpc_security_group_ids              = [aws_security_group.neptune.id]

  tags = {
    Name = "neptune-cluster"
  }
}

# Neptune Cluster Instance
resource "aws_neptune_cluster_instance" "main" {
  count              = 1
  cluster_identifier = aws_neptune_cluster.main.id
  engine             = "neptune"
  instance_class     = "db.t3.medium"
  identifier         = "neptune-instance-${count.index}"

  tags = {
    Name = "neptune-instance-${count.index}"
  }
}

