# VPC and Subnet for Neptune
resource "aws_vpc" "example" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "neptune-vpc"
  }
}

resource "aws_subnet" "example_1" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "neptune-subnet-1"
  }
}

resource "aws_subnet" "example_2" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[1]

  tags = {
    Name = "neptune-subnet-2"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Neptune Subnet Group
resource "aws_neptune_subnet_group" "example" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.example_1.id, aws_subnet.example_2.id]

  tags = {
    Name = "Neptune subnet group"
  }
}

# Security Group - Only allow connections from example subnet
resource "aws_security_group" "neptune" {
  name        = "neptune-sg"
  description = "Security group for Neptune cluster"
  vpc_id      = aws_vpc.example.id

  ingress {
    description = "Neptune from example subnet"
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.example_1.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-security-group"
  }
}

