resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "redshift-vpc"
  }
}

resource "aws_subnet" "subnet1" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "redshift-subnet-1"
  }
}

resource "aws_subnet" "subnet2" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "redshift-subnet-2"
  }
}

resource "aws_redshift_subnet_group" "example" {
  name       = "example-redshift-subnet-group"
  subnet_ids = [aws_subnet.subnet1.id, aws_subnet.subnet2.id]

  tags = {
    Name = "example-redshift-subnet-group"
  }
}

resource "random_password" "redshift_password" {
  length  = 16
  special = false
}

resource "aws_redshift_cluster" "example" {
  cluster_identifier  = "example-redshift-cluster"
  database_name       = "exampledb"
  master_username     = "exampleuser"
  master_password     = random_password.redshift_password.result
  node_type           = "dc2.large"
  cluster_type        = "single-node"
  cluster_subnet_group_name = aws_redshift_subnet_group.example.name
  skip_final_snapshot = true

  tags = {
    Name = "example-redshift-cluster"
  }
}

resource "aws_redshift_endpoint_access" "example" {
  endpoint_name      = "example-endpoint"
  subnet_group_name  = aws_redshift_subnet_group.example.name
  cluster_identifier = aws_redshift_cluster.example.cluster_identifier
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_redshift_cluster" "example" {
  cluster_identifier = "tf-redshift-cluster"
  database_name      = "mydb"
  master_username    = "exampleuser"
  master_password    = "Mustbe8characters"
  node_type          = "ra3.xlplus"
  cluster_type       = "single-node"
}

resource "aws_redshift_endpoint_access" "example" {
  endpoint_name      = "example"
  subnet_group_name  = aws_redshift_subnet_group.foobar.id
  cluster_identifier = aws_redshift_cluster.example.cluster_identifier
}

resource "aws_vpc" "foo" {
  cidr_block = "10.1.0.0/16"
}

data "aws_availability_zones" "azs" {
    state = "available"
}

resource "aws_subnet" "foo" {
  cidr_block        = "10.1.1.0/24"
  availability_zone = data.aws_availability_zones.azs.names[0]
  vpc_id            = aws_vpc.foo.id
}

resource "aws_subnet" "bar" {
  cidr_block        = "10.1.2.0/24"
  availability_zone = data.aws_availability_zones.azs.names[1]
  vpc_id            = aws_vpc.foo.id
}

resource "aws_redshift_subnet_group" "foobar" {
  name       = "foo"
  subnet_ids = [aws_subnet.foo.id, aws_subnet.bar.id]
}

