# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "autograder_logs" {
  name              = "/aws/codebuild/autograder-${random_id.suffix.hex}"
  retention_in_days = 7
}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograder" {
  name          = "autograder-project-${random_id.suffix.hex}"
  description   = "Autograder for CS class assignments"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = 30

  artifacts {
    type = "S3"
    location = aws_s3_bucket.codebuild_artifacts.bucket
    packaging = "ZIP"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                      = "aws/codebuild/standard:7.0"
    type                       = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.autograder_results.bucket
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name = aws_cloudwatch_log_group.autograder_logs.name
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-organization/student-repos.git"
    git_clone_depth = 1
    buildspec = yamlencode({
      version = "0.2"
      phases = {
        install = {
          commands = [
            "echo Installing dependencies...",
            "# Add language-specific dependency installation here"
          ]
        }
        build = {
          commands = [
            "echo Running autograder tests...",
            "# Add test execution commands here",
            "echo Generating results..."
          ]
        }
        post_build = {
          commands = [
            "echo Uploading results to S3...",
            "TIMESTAMP=$(date +%Y%m%d-%H%M%S)",
            "aws s3 cp results.json s3://$RESULTS_BUCKET/$CODEBUILD_INITIATOR/$TIMESTAMP/results.json || true"
          ]
        }
      }
      artifacts = {
        files = [
          "results.json",
          "**/*"
        ]
      }
    })
  }
}

