# VPC for isolated autograding environment
resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc"
  }
}

# Private subnet for CodeBuild (no internet access)
resource "aws_subnet" "autograder_private" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "autograder-private-subnet"
  }
}

# Security group for CodeBuild - no outbound internet access
resource "aws_security_group" "autograder_sg" {
  name        = "autograder-sg"
  description = "Security group for autograder - blocks internet access"
  vpc_id      = aws_vpc.autograder_vpc.id

  # No ingress rules needed
  # Egress only within VPC
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
  }

  tags = {
    Name = "autograder-sg"
  }
}

# VPC endpoint for S3 (to store results without internet)
resource "aws_vpc_endpoint" "s3" {
  vpc_id       = aws_vpc.autograder_vpc.id
  service_name = "com.amazonaws.${data.aws_region.current.name}.s3"
  route_table_ids = [aws_route_table.autograder_private.id]

  tags = {
    Name = "autograder-s3-endpoint"
  }
}

# Route table for private subnet
resource "aws_route_table" "autograder_private" {
  vpc_id = aws_vpc.autograder_vpc.id

  tags = {
    Name = "autograder-private-rt"
  }
}

resource "aws_route_table_association" "autograder_private" {
  subnet_id      = aws_subnet.autograder_private.id
  route_table_id = aws_route_table.autograder_private.id
}

# S3 bucket to store autograding results
resource "aws_s3_bucket" "autograder_results" {
  bucket = "autograder-results-${random_id.suffix.hex}"

  tags = {
    Name = "autograder-results"
  }
}

resource "aws_s3_bucket_versioning" "autograder_results" {
  bucket = aws_s3_bucket.autograder_results.id
  versioning_configuration {
    status = "Enabled"
  }
}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for CodeBuild
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:log-group:/aws/codebuild/autograder*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ]
        Resource = "${aws_s3_bucket.autograder_results.arn}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeVpcs",
          "ec2:CreateNetworkInterfacePermission"
        ]
        Resource = "*"
      }
    ]
  })
}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograder" {
  name          = "autograder-project"
  description   = "Autograder for CS class assignments"
  build_timeout = 30
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.autograder_results.id
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/student-submissions.git"
    git_clone_depth = 1
    buildspec       = <<-EOT
      version: 0.2
      phases:
        install:
          commands:
            - echo "Installing dependencies"
        build:
          commands:
            - echo "Running autograder tests"
            - echo "Student code is isolated from internet"
            - python3 run_tests.py
        post_build:
          commands:
            - echo "Uploading results to S3"
            - aws s3 cp results.json s3://$RESULTS_BUCKET/results/$STUDENT_ID/results.json
    EOT
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnets            = [aws_subnet.autograder_private.id]
    security_group_ids = [aws_security_group.autograder_sg.id]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/autograder"
      stream_name = "autograder-logs"
    }
  }

  tags = {
    Name = "autograder"
  }
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "autograder" {
  name              = "/aws/codebuild/autograder"
  retention_in_days = 7
}

# Random suffix for unique resource names
resource "random_id" "suffix" {
  byte_length = 4
}

# Data sources
data "aws_availability_zones" "available" {
  state = "available"
