      value = aws_s3_bucket.autograder_results.id
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name = aws_cloudwatch_log_group.autograder_logs.name
      status     = "ENABLED"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/student-submissions.git"
    git_clone_depth = 1
    buildspec       = <<-EOF
      version: 0.2
      phases:
        install:
          commands:
            - echo "Installing dependencies..."
        build:
          commands:
            - echo "Running autograder tests..."
            - echo "Student code will run here in isolated environment"
            - echo "Results will be stored in S3"
        post_build:
          commands:
            - echo "Uploading results to S3..."
            - aws s3 cp results.json s3://$RESULTS_BUCKET/results/$(date +%Y%m%d-%H%M%S)-results.json
    EOF
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnets            = [aws_subnet.autograder_private_subnet.id]
    security_group_ids = [aws_security_group.autograder_sg.id]
  }

  tags = {
    Name = "autograder-project"
  }
}

# Data sources
data "aws_availability_zones" "available" {
  state = "available"
}

data "aws_region" "current" {}

data "aws_caller_identity" "current" {}
```

