    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "lambda.amazonaws.com"
      }
    }]
  })
}

# IAM Policy for GET Lambda (S3 and DynamoDB read access)
resource "aws_iam_role_policy" "get_lambda_policy" {
  name = "caas_get_lambda_policy"
  role = aws_iam_role.get_lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
