    type             = "forward"
    target_group_arn = aws_lb_target_group.video_streaming.arn
  }
}

# Route53 Hosted Zone
resource "aws_route53_zone" "video_streaming" {
  name = "videostreaming.example.com"

  tags = {
    Name = "video-streaming-zone"
  }
}

# Route53 Record
resource "aws_route53_record" "video_streaming" {
  zone_id = aws_route53_zone.video_streaming.zone_id
  name    = "www.videostreaming.example.com"
