# Create VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc-${random_id.suffix.hex}"
  }
}

# Get availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

# Create first subnet
resource "aws_subnet" "subnet_1" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = data.aws_availability_zones.available.names[0]
  map_public_ip_on_launch = true

  tags = {
    Name = "subnet-1-${random_id.suffix.hex}"
  }
}

# Create second subnet
resource "aws_subnet" "subnet_2" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = data.aws_availability_zones.available.names[1]
  map_public_ip_on_launch = true

  tags = {
    Name = "subnet-2-${random_id.suffix.hex}"
  }
}

# Create Internet Gateway for public accessibility
resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw-${random_id.suffix.hex}"
  }
}

# Create route table
resource "aws_route_table" "main" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }

  tags = {
    Name = "main-rt-${random_id.suffix.hex}"
  }
}

# Associate route table with subnets
resource "aws_route_table_association" "subnet_1" {
  subnet_id      = aws_subnet.subnet_1.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "subnet_2" {
  subnet_id      = aws_subnet.subnet_2.id
  route_table_id = aws_route_table.main.id
}

# Create DB subnet group
resource "aws_db_subnet_group" "main" {
  name       = "main-db-subnet-group-${random_id.suffix.hex}"
  subnet_ids = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  tags = {
    Name = "main-db-subnet-group"
  }
}

# Create security group for database access
resource "aws_security_group" "db_access" {
  name        = "db-access-sg-${random_id.suffix.hex}"
  description = "Security group for database access"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    description = "Allow all outbound traffic"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "db-access-sg-${random_id.suffix.hex}"
  }
}

# Create RDS PostgreSQL instance
resource "aws_db_instance" "postgres" {
  identifier              = "postgres-db-${random_id.suffix.hex}"
  allocated_storage       = 20
  engine                  = "postgres"
  engine_version          = "15.3"
  instance_class          = "db.t3.micro"
  db_name                 = "postgresdb"
  username                = "dbadmin"
  password                = random_password.db_password.result
  db_subnet_group_name    = aws_db_subnet_group.main.name
  vpc_security_group_ids  = [aws_security_group.db_access.id]
  publicly_accessible     = true
  skip_final_snapshot     = true

  tags = {
    Name = "postgres-db-${random_id.suffix.hex}"
  }
}

# Output the database endpoint
output "database_endpoint" {
  description = "The connection endpoint for the RDS instance"
  value       = aws_db_instance.postgres.endpoint
}

output "database_name" {
  description = "The name of the database"
  value       = aws_db_instance.postgres.db_name
}

output "database_username" {
  description = "The master username for the database"
  value       = aws_db_instance.postgres.username
  sensitive   = true
}

output "database_password" {
  description = "The master password for the database"
  value       = random_password.db_password.result
  sensitive   = true
}

