resource "aws_glacier_vault_lock" "archive_lock" {
  complete_lock = false
  vault_name    = aws_glacier_vault.archive.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "DenyDeleteArchive"
        Effect = "Deny"
        Principal = {
          AWS = "*"
        }
        Action = [
          "glacier:DeleteArchive"
        ]
        Resource = aws_glacier_vault.archive.arn
      }
    ]
  })
}

resource "aws_sns_topic" "glacier_notifications" {
  name = "glacier-vault-notifications"
}

resource "aws_glacier_vault" "archive_with_notifications" {
  name = "long-term-archive-vault-notifications"

  notification {
    sns_topic = aws_sns_topic.glacier_notifications.arn
    events    = ["ArchiveRetrievalCompleted", "InventoryRetrievalCompleted"]
  }

  tags = {
    Name        = "Archive Vault with Notifications"
    Environment = "production"
  }
}

